import requests
import json

class RabbitMQConfigurator:
    def __init__(self, api_base_url, api_username, api_password):
        self.api_base_url = api_base_url
        self.auth = (api_username, api_password)
        self.headers = {'Content-Type': 'application/json'}

    def _api_call(self, method, endpoint, data=None):
        url = f"{self.api_base_url}{endpoint}"
        try:
            if method == 'GET':
                response = requests.get(url, auth=self.auth)
            elif method == 'PUT':
                response = requests.put(url, auth=self.auth, data=json.dumps(data), headers=self.headers)
            elif method == 'POST':
                response = requests.post(url, auth=self.auth, data=json.dumps(data), headers=self.headers)
            elif method == 'DELETE':
                response = requests.delete(url, auth=self.auth)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")

            response.raise_for_status()
            if response.status_code == 204: # No content for successful DELETE
                return None
            return response.json() if response.content else None
        except requests.exceptions.RequestException as e:
            print(f"API call failed for {method} {url}: {e}")
            if hasattr(e, 'response') and e.response is not None:
                print(f"Response status: {e.response.status_code}")
                print(f"Response body: {e.response.text}")
            return None

    def create_vhost(self, vhost_name):
        print(f"Attempting to create vhost: {vhost_name}")
        response = self._api_call('PUT', f'/api/vhosts/{vhost_name}')
        if response is not None:
            print(f"Vhost '{vhost_name}' created successfully (or already exists).")
            return True
        return False

    def create_user(self, username, password, tags=""):
        print(f"Attempting to create user: {username}")
        data = {
            "password": password,
            "tags": tags
        }
        response = self._api_call('PUT', f'/api/users/{username}', data)
        if response is not None:
            print(f"User '{username}' created successfully (or already exists).")
            return True
        return False

    def set_permissions(self, vhost_name, username, configure_regex=".*", write_regex=".*", read_regex=".*"):
        print(f"Attempting to set permissions for user '{username}' on vhost '{vhost_name}'")
        data = {
            "configure": configure_regex,
            "write": write_regex,
            "read": read_regex
        }
        response = self._api_call('PUT', f'/api/permissions/{vhost_name}/{username}', data)
        if response is not None:
            print(f"Permissions for user '{username}' on vhost '{vhost_name}' set successfully.")
            return True
        return False

    def delete_vhost(self, vhost_name):
        print(f"Attempting to delete vhost: {vhost_name}")
        response = self._api_call('DELETE', f'/api/vhosts/{vhost_name}')
        if response is None:
            print(f"Vhost '{vhost_name}' deleted successfully.")
            return True
        return False

    def delete_user(self, username):
        print(f"Attempting to delete user: {username}")
        response = self._api_call('DELETE', f'/api/users/{username}')
        if response is None:
            print(f"User '{username}' deleted successfully.")
            return True
        return False

